import { spawn } from "node:child_process";
import fs from "node:fs";
import path from "node:path";

const logDir = "/home/user/myproject/logs";
const logFilePath = path.join(logDir, "access.log");

if (!fs.existsSync(logDir)) {
  fs.mkdirSync(logDir, { recursive: true });
}

const child = spawn("npx", ["vite", "dev"], {
  stdio: ["inherit", "pipe", "inherit"],
});

let buffer = "";

child.stdout.on("data", (data) => {
  const str = data.toString();
  process.stdout.write(str);

  buffer += str;
  let lines = buffer.split("\n");
  buffer = lines.pop() || "";

  for (const line of lines) {
    if (line.includes("[ACCESS_LOG]")) {
      const idx = line.indexOf("[ACCESS_LOG]");
      const jsonPart = line.slice(idx + "[ACCESS_LOG] ".length).trim();
      if (jsonPart) {
        fs.appendFileSync(logFilePath, jsonPart + "\n");
      }
    }
  }
});

child.on("close", (code) => {
  process.exit(code || 0);
});

